 p=argparse.ArgumentParser();p.add_argument('--output-dir',type=Path,required=True);a=p.parse_args();o=a.output_dir
 r=json.loads((o/'legal-overlay-result.json').read_text());g=json.loads((o/'updated-gap-register.json').read_text());idx=json.loads((o/'legal-overlay-index.json').read_text());m=json.loads((o/'legal/component-license-map-candidate-v2.json').read_text());xz=json.loads((o/'legal/xz-product-license-evidence.json').read_text());sq=json.loads((o/'legal/sqlite-public-domain-evidence.json').read_text());h=json.loads((o/'legal/hacl-star-license-evidence.json').read_text());pdoc=json.loads((o/'legal/android-system-provider-policy.json').read_text())
