 failed=sorted(k for k,v in checks.items() if v is not True);out={'schema_version':1,'audit_kind':'epoch3-rb1-legal-overlay-independent-audit','pass':not failed,'checks':dict(sorted(checks.items())),'failed_checks':failed,'input_sha256':{'legal-overlay-result.json':sha(o/'legal-overlay-result.json'),'updated-gap-register.json':sha(o/'updated-gap-register.json'),'legal-overlay-index.json':sha(o/'legal-overlay-index.json')},'legal_overlay_fingerprint_sha256':fp,'claim_boundary':{'component_license_mapping_complete':False,'complete_obligation_review':False,'legal_overlay_authoritative':False,'rb1_closed':False,'selectable':False,'publication':False}};print(json.dumps(out,indent=2,sort_keys=True));return 0 if out['pass'] else 1
